export function getTopicById(id: string): Topic | undefined {
  return topics.find((t) => t.id === id);
}

export function getTopicsBySubcategory(subcategory: string): Topic[] {
  return topics.filter((t) => t.subcategory === subcategory);
}

export function getTopicsByCategory(category: string): Topic[] {
  return topics.filter((t) => t.category === category);
}

export function getTopicsByModule(mod: 1 | 2): Topic[] {
  return topics.filter((t) => t.module === mod);
}

export function getSubcategories(): string[] {
  return Array.from(new Set(topics.map((t) => t.subcategory)));
}

export function getTopicsByCourse(course: Course) {
  return topics.filter((t) => t.course === course);
}
